    40→const DEFAULT_ENGINE_CONFIG: Partial<EngineConfig> = {
    41→  ltfPeriodMs: 15 * 60 * 1000,
    42→  htfPeriodMs: 4 * 60 * 60 * 1000,
    43→  autoTrade: false,
    44→  maxLTFCandles: 200,
    45→  maxHTFCandles: 100,
    46→};
    47→
    48→/**
    49→ * RealtimeEngine — Event-driven trading engine.
    50→ *
    51→ * Accepts candle data via `pushCandle()` and emits signals when
    52→ * the analysis pipeline produces tradeable setups.
    53→ *
    54→ * Events:
    55→ * - 'signal': Emitted when analysis produces a SignalResult
    56→ * - 'trade_entry': Emitted when a trade is executed (autoTrade=true)
    57→ * - 'trade_exit': Emitted when a trade is closed
    58→ * - 'session_halt': Emitted when circuit breaker triggers
    59→ * - 'session_reset': Emitted when session resets
    60→ * - 'error': Emitted on analysis errors
    61→ * - 'candle': Emitted when a new candle is received
    62→ */
    63→export class RealtimeEngine extends EventEmitter {
    64→  private readonly analyzer: SMCAnalyzer;
    65→  private readonly config: EngineConfig;
    66→  private ltfCandles: Candle[] = [];
    67→  private htfCandles: Candle[] = [];
    68→  private currentMacro: MacroContext;
    69→  private activeTrade: TradeExecution | null = null;
    70→  private signalCounter = 0;
    71→  private running = false;
    72→
    73→  constructor(config: Partial<EngineConfig> & { symbol: string; capital: number }) {
    74→    super();
    75→    this.config = { ...DEFAULT_ENGINE_CONFIG, ...config } as EngineConfig;
    76→    this.analyzer = new SMCAnalyzer(this.config.symbol, this.config.capital);
    77→    this.currentMacro = {
    78→      dxy: { trend: 'RANGING', implication: 'NEUTRAL' },
    79→      vix: { level: 18, interpretation: 'NORMAL', sizingMultiplier: 1.0 },
    80→      newsFilter: { highImpactToday: false, noTradeWindow: false },
    81→    };
    82→  }
    83→
    84→  /** Start the engine */
    85→  start(): void {
    86→    this.running = true;
    87→    this.emit('session_reset', { date: new Date().toISOString().slice(0, 10) });
    88→  }
    89→
    90→  /** Stop the engine */
    91→  stop(): void {
    92→    this.running = false;
    93→  }
    94→
    95→  /** Check if the engine is running */
    96→  isRunning(): boolean {
    97→    return this.running;
    98→  }
    99→
   100→  /** Push a new LTF candle and trigger analysis */
   101→  pushLTFCandle(candle: Candle): void {
   102→    if (!this.running) return;
   103→
   104→    this.ltfCandles.push(candle);
   105→    if (this.ltfCandles.length > this.config.maxLTFCandles) {
   106→      this.ltfCandles = this.ltfCandles.slice(-this.config.maxLTFCandles);
   107→    }
   108→
   109→    this.emit('candle', { timeframe: 'LTF', candle });
   110→    this.runAnalysis();
   111→  }
   112→
   113→  /** Push a new HTF candle */
   114→  pushHTFCandle(candle: Candle): void {
   115→    if (!this.running) return;
   116→
   117→    this.htfCandles.push(candle);
   118→    if (this.htfCandles.length > this.config.maxHTFCandles) {
   119→      this.htfCandles = this.htfCandles.slice(-this.config.maxHTFCandles);
   120→    }
   121→
   122→    this.emit('candle', { timeframe: 'HTF', candle });
   123→  }
   124→
   125→  /** Update macro context (DXY, VIX, news) */
   126→  updateMacro(macro: MacroContext): void {
   127→    this.currentMacro = macro;
   128→  }
   129→
   130→  /** Get the current active trade */
   131→  getActiveTrade(): TradeExecution | null {
   132→    return this.activeTrade;
   133→  }
   134→
   135→  /** Manually record a trade result */
   136→  recordTradeResult(result: 'WIN' | 'LOSS' | 'BE', pnl: number): void {
   137→    this.analyzer.recordTradeResult(result, pnl);
   138→
   139→    if (this.activeTrade) {
   140→      this.emit('trade_exit', {
   141→        trade: this.activeTrade,
   142→        result,
   143→        pnl,
   144→      });
   145→      this.activeTrade = null;
   146→    }
   147→
   148→    if (this.analyzer.getSessionState().isHalted) {
   149→      this.emit('session_halt', {
   150→        reason: this.analyzer.getSessionState().haltReason,
   151→      });
   152→    }
   153→  }
   154→
   155→  /** Get current session state */
   156→  getSessionState() {
   157→    return this.analyzer.getSessionState();
   158→  }
   159→
   160→  /** Reset session for a new trading day */
   161→  resetSession(date?: string): void {
   162→    this.analyzer.resetSession(date);
   163→    this.emit('session_reset', { date: date ?? new Date().toISOString().slice(0, 10) });
   164→  }
   165→
   166→  /** Get count of LTF candles in buffer */
   167→  getLTFCandleCount(): number {
   168→    return this.ltfCandles.length;
   169→  }
   170→
   171→  /** Get count of HTF candles in buffer */
   172→  getHTFCandleCount(): number {
   173→    return this.htfCandles.length;
   174→  }
   175→
   176→  /** Run the analysis pipeline */
   177→  private runAnalysis(): void {
   178→    if (this.ltfCandles.length < 20 || this.htfCandles.length < 20) return;
   179→
   180→    try {
   181→      const signal = this.analyzer.analyze(
   182→        this.ltfCandles,
   183→        this.htfCandles,
   184→        this.currentMacro,
   185→      );
   186→
   187→      this.emit('signal', signal);
   188→
   189→      // Auto-trade execution
   190→      if (this.config.autoTrade && signal.isTradable && signal.entry && !this.activeTrade) {
   191→        this.signalCounter++;
   192→        const trade: TradeExecution = {
   193→          signalId: `${this.config.symbol}-${this.signalCounter}`,
   194→          direction: signal.direction,
   195→          entryPrice: signal.entry.price,
   196→          stopLoss: signal.entry.stopLoss,
   197→          tp1: signal.entry.tp1,
   198→          tp2: signal.entry.tp2,
   199→          tp3: signal.entry.tp3,
   200→          positionSize: signal.entry.positionSize,
   201→          timestamp: signal.timestamp,
   202→        };
   203→
   204→        this.activeTrade = trade;
   205→        this.emit('trade_entry', trade);
   206→      }
   207→    } catch (error) {
   208→      const msg = error instanceof Error ? error.message : 'Unknown engine error';
   209→      this.emit('error', { message: msg, timestamp: Date.now() });
   210→    }
   211→  }
   212→}
