    55→/**
    56→ * TradeJournal — Persistence layer for trade records, signal logs, and session state.
    57→ *
    58→ * Stores data as JSON files in a configurable directory.
    59→ * Provides statistics and reporting.
    60→ */
    61→export class TradeJournal {
    62→  private readonly dataDir: string;
    63→  private trades: TradeRecord[] = [];
    64→  private signalLog: SignalLogEntry[] = [];
    65→
    66→  constructor(dataDir: string = './data') {
    67→    this.dataDir = dataDir;
    68→    this.ensureDir();
    69→    this.loadState();
    70→  }
    71→
    72→  /** Record a new signal from the analysis pipeline */
    73→  logSignal(signal: SignalResult, symbol: string): void {
    74→    const entry: SignalLogEntry = {
    75→      timestamp: signal.timestamp,
    76→      symbol,
    77→      isTradable: signal.isTradable,
    78→      direction: signal.direction,
    79→      score: signal.score.total,
    80→      grade: signal.score.grade,
    81→      disqualifications: signal.disqualifications,
    82→      htfBias: signal.context.htfBias,
    83→      killZone: signal.context.killZone,
    84→      sessionStatus: signal.sessionStatus,
    85→    };
    86→
    87→    this.signalLog.push(entry);
    88→
    89→    // Keep last 1000 signals
    90→    if (this.signalLog.length > 1000) {
    91→      this.signalLog = this.signalLog.slice(-1000);
    92→    }
    93→
    94→    this.saveSignalLog();
    95→  }
    96→
    97→  /** Record a trade entry */
    98→  recordEntry(trade: TradeRecord): void {
    99→    this.trades.push(trade);
   100→    this.saveTrades();
   101→  }
   102→
   103→  /** Record a trade exit */
   104→  recordExit(tradeId: string, result: 'WIN' | 'LOSS' | 'BE', exitPrice: number, pnl: number): void {
   105→    const trade = this.trades.find(t => t.id === tradeId);
   106→    if (trade) {
   107→      // Since records are readonly, create a new one
   108→      const idx = this.trades.indexOf(trade);
   109→      this.trades[idx] = {
   110→        ...trade,
   111→        result,
   112→        exitPrice,
   113→        pnl,
   114→        closedAt: Date.now(),
   115→      };
   116→      this.saveTrades();
   117→    }
   118→  }
   119→
   120→  /** Save session state */
   121→  saveSessionState(state: SessionState, symbol: string): void {
   122→    const filePath = join(this.dataDir, `session-${symbol}.json`);
   123→    writeFileSync(filePath, JSON.stringify(state, null, 2), 'utf-8');
   124→  }
   125→
   126→  /** Load session state */
   127→  loadSessionState(symbol: string): SessionState | null {
   128→    const filePath = join(this.dataDir, `session-${symbol}.json`);
   129→    if (!existsSync(filePath)) return null;
   130→    try {
   131→      return JSON.parse(readFileSync(filePath, 'utf-8'));
   132→    } catch {
   133→      return null;
   134→    }
   135→  }
   136→
   137→  /** Get all trades */
   138→  getTrades(): readonly TradeRecord[] {
   139→    return this.trades;
   140→  }
   141→
   142→  /** Get trades for a specific date */
   143→  getTradesByDate(date: string): TradeRecord[] {
   144→    return this.trades.filter(t => t.date === date);
   145→  }
   146→
   147→  /** Get recent signals */
   148→  getRecentSignals(limit: number = 50): readonly SignalLogEntry[] {
   149→    return this.signalLog.slice(-limit);
   150→  }
   151→
   152→  /** Calculate trade statistics */
   153→  getStats(): JournalStats {
   154→    const closed = this.trades.filter(t => t.result !== undefined);
   155→
   156→    if (closed.length === 0) {
   157→      return {
   158→        totalTrades: 0, wins: 0, losses: 0, breakEvens: 0,
   159→        winRate: 0, totalPnL: 0, averageWin: 0, averageLoss: 0,
   160→        profitFactor: 0, maxConsecutiveWins: 0, maxConsecutiveLosses: 0,
   161→        sharpeApprox: 0,
   162→      };
   163→    }
   164→
   165→    const wins = closed.filter(t => t.result === 'WIN');
   166→    const losses = closed.filter(t => t.result === 'LOSS');
   167→    const breakEvens = closed.filter(t => t.result === 'BE');
   168→
   169→    const winPnLs = wins.map(t => t.pnl ?? 0);
   170→    const lossPnLs = losses.map(t => t.pnl ?? 0);
   171→    const allPnLs = closed.map(t => t.pnl ?? 0);
   172→
   173→    const totalPnL = allPnLs.reduce((a, b) => a + b, 0);
   174→    const avgWin = winPnLs.length > 0 ? winPnLs.reduce((a, b) => a + b, 0) / winPnLs.length : 0;
   175→    const avgLoss = lossPnLs.length > 0 ? Math.abs(lossPnLs.reduce((a, b) => a + b, 0) / lossPnLs.length) : 0;
   176→    const grossWins = winPnLs.reduce((a, b) => a + b, 0);
   177→    const grossLosses = Math.abs(lossPnLs.reduce((a, b) => a + b, 0));
   178→
   179→    // Consecutive tracking
   180→    let maxConsecWins = 0;
   181→    let maxConsecLosses = 0;
   182→    let currentConsecWins = 0;
   183→    let currentConsecLosses = 0;
   184→
   185→    for (const t of closed) {
   186→      if (t.result === 'WIN') {
   187→        currentConsecWins++;
   188→        currentConsecLosses = 0;
   189→        maxConsecWins = Math.max(maxConsecWins, currentConsecWins);
   190→      } else if (t.result === 'LOSS') {
   191→        currentConsecLosses++;
   192→        currentConsecWins = 0;
   193→        maxConsecLosses = Math.max(maxConsecLosses, currentConsecLosses);
   194→      } else {
   195→        currentConsecWins = 0;
   196→        currentConsecLosses = 0;
   197→      }
   198→    }
   199→
   200→    // Sharpe approximation: mean(pnl) / std(pnl)
   201→    const mean = totalPnL / closed.length;
   202→    const variance = allPnLs.reduce((sum, p) => sum + (p - mean) ** 2, 0) / closed.length;
   203→    const std = Math.sqrt(variance);
   204→    const sharpe = std > 0 ? mean / std : 0;
   205→
   206→    return {
   207→      totalTrades: closed.length,
   208→      wins: wins.length,
   209→      losses: losses.length,
   210→      breakEvens: breakEvens.length,
   211→      winRate: wins.length / closed.length,
   212→      totalPnL,
   213→      averageWin: avgWin,
   214→      averageLoss: avgLoss,
   215→      profitFactor: grossLosses > 0 ? grossWins / grossLosses : grossWins > 0 ? Infinity : 0,
   216→      maxConsecutiveWins: maxConsecWins,
   217→      maxConsecutiveLosses: maxConsecLosses,
   218→      sharpeApprox: Math.round(sharpe * 100) / 100,
   219→    };
   220→  }
   221→
   222→  private ensureDir(): void {
   223→    if (!existsSync(this.dataDir)) {
   224→      mkdirSync(this.dataDir, { recursive: true });
   225→    }
   226→  }
   227→
   228→  private saveTrades(): void {
   229→    const filePath = join(this.dataDir, 'trades.json');
   230→    writeFileSync(filePath, JSON.stringify(this.trades, null, 2), 'utf-8');
   231→  }
   232→
   233→  private saveSignalLog(): void {
   234→    const filePath = join(this.dataDir, 'signals.json');
   235→    writeFileSync(filePath, JSON.stringify(this.signalLog, null, 2), 'utf-8');
   236→  }
   237→
   238→  private loadState(): void {
   239→    const tradesPath = join(this.dataDir, 'trades.json');
   240→    if (existsSync(tradesPath)) {
   241→      try {
   242→        this.trades = JSON.parse(readFileSync(tradesPath, 'utf-8'));
   243→      } catch {
   244→        this.trades = [];
   245→      }
   246→    }
   247→
   248→    const signalsPath = join(this.dataDir, 'signals.json');
   249→    if (existsSync(signalsPath)) {
   250→      try {
   251→        this.signalLog = JSON.parse(readFileSync(signalsPath, 'utf-8'));
   252→      } catch {
   253→        this.signalLog = [];
   254→      }
   255→    }
   256→  }
   257→}
